import Dashboard from "./pages/Dashboard";

function App() {
  return (
    <div className="bg-gray-100 min-h-screen">
      <header className="bg-[#1f2937] text-white px-6 py-4 shadow">
        <h1 className="text-2xl font-bold tracking-wide">🛡️ Suricata Alert Dashboard</h1>
      </header>
      <main className="py-6 px-4 sm:px-8 md:px-16">
        <Dashboard />
      </main>
    </div>
  );
}

export default App;
